    int pairs[n][2];

    for (int i = 0; i < n; ++i) {
        scanf("%d %d", &pairs[i][0], &pairs[i][1]);
    }

    for (int i = 0; i < n; ++i) {
        if ((pairs[i][0] + pairs[i][1]) % k == 0) {
            printf("(%d, %d)\n", pairs[i][0], pairs[i][1]);
        }
    }

    return 0;
